#include <stdio.h>
#include <stdlib.h>
#define MAX 105
int max(int a, int b) { return a > b ? a : b; }
int dp[MAX][MAX][MAX];
int main() {
    int N, X, Y;
    scanf("%d %d %d", &N, &X, &Y);
    int A[N], B[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    for (int i = 0; i < N; i++) {
        scanf("%d", &B[i]);
    }
    for (int i = 0; i <= N; i++) {
        for (int j = 0; j <= X; j++) {
            for (int k = 0; k <= Y; k++) {
                if (i == 0) {
                    dp[i][j][k] = 0;
                } else if (j > 0 && k > 0) {
                    dp[i][j][k] = max(dp[i-1][j-1][k] + A[i-1], dp[i-1][j][k-1] + B[i-1]);
                } else if (j > 0) {
                    dp[i][j][k] = dp[i-1][j-1][k] + A[i-1];
                } else if (k > 0) {
                    dp[i][j][k] = dp[i-1][j][k-1] + B[i-1];
                }
            }
        }
    }
    int ans = 0;
    for (int j = 0; j <= X; j++) {
        for (int k = 0; k <= Y; k++) {
            if (j + k == N) {
                ans = max(ans, dp[N][j][k]);
            }
        }
    }
    printf("%d\n", ans);
    return 0;
}

