    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int X = sc.nextInt();
        int Y = sc.nextInt();
        int[] A = new int[N];
        int[] B = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        for (int i = 0; i < N; i++) {
            B[i] = sc.nextInt();
        }
        int[][][] dp = new int[N + 1][X + 1][Y + 1];
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= X; j++) {
                for (int k = 0; k <= Y; k++) {
                    if (i == 0) {
                        dp[i][j][k] = 0;
                    } else if (j > 0 && k > 0) {
                        dp[i][j][k] = Math.max(dp[i-1][j-1][k] + A[i-1], dp[i-1][j][k-1] + B[i-1]);
                    } else if (j > 0) {
                        dp[i][j][k] = dp[i-1][j-1][k] + A[i-1];
                    } else if (k > 0) {
                        dp[i][j][k] = dp[i-1][j][k-1] + B[i-1];
                    }
                }
            }
        }
        int ans = 0;
        for (int j = 0; j <= X; j++) {
            for (int k = 0; k <= Y; k++) {
                if (j + k == N) {
                    ans = Math.max(ans, dp[N][j][k]);
                }
            }
        }
        System.out.println(ans);
    }
}

